example.code:
// Step 1 — preview, no side effect
{ "name": "deploy_preview",
  "input":  { "service": "nero-core", "ref": "main" },
  "output": { "diff": "+2 -1 services...", "estimated_cost_usd": 0.04,
              "preview_hash": "sha256:abc123" } }

// Step 2 — apply, idempotent, refers to the exact preview
{ "name": "deploy_apply",
  "input":  { "preview_hash": "sha256:abc123",
              "idempotency_key": "deploy-2026-04-25-001" },
  "output": { "deployment_id": "dep_91f2", "status": "succeeded" } }
